// Step 1: Call GPT-SoVITS TTS
const jobId = $('Extract Fields').item.json.job_id;
const scriptText = $('Extract Fields').item.json.script_text;
const channelId = $('Extract Fields').item.json.channel_id;
const userId = $('Extract Fields').item.json.user_id;

const ttsBody = {
  text: scriptText,
  text_lang: $env.TTS_TEXT_LANG || 'ko',
  ref_audio_path: $env.TTS_REF_AUDIO_PATH,
  prompt_text: $env.TTS_PROMPT_TEXT,
  prompt_lang: $env.TTS_PROMPT_LANG || 'ko',
  media_type: 'wav',
  streaming_mode: false
};

const ttsResp = await fetch(`${$env.TTS_API_URL}/tts`, {
  method: 'POST',
  headers: { 'Content-Type': 'application/json' },
  body: JSON.stringify(ttsBody)
});

if (!ttsResp.ok) {
  throw new Error(`TTS API failed: ${ttsResp.status} ${await ttsResp.text()}`);
}

const audioBuffer = await ttsResp.arrayBuffer();
const audioBytes = new Uint8Array(audioBuffer);

// Step 2: Upload audio to HeyGen
const formData = new FormData();
const audioBlob = new Blob([audioBytes], { type: 'audio/wav' });
formData.append('file', audioBlob, 'audio.wav');

const uploadResp = await fetch('https://upload.heygen.com/v1/asset', {
  method: 'POST',
  headers: { 'X-Api-Key': $env.HEYGEN_API_KEY },
  body: formData
});

if (!uploadResp.ok) {
  throw new Error(`HeyGen upload failed: ${uploadResp.status} ${await uploadResp.text()}`);
}

const uploadData = await uploadResp.json();
const assetId = uploadData.data?.id || uploadData.asset_id;
if (!assetId) {
  throw new Error(`HeyGen upload returned no asset_id: ${JSON.stringify(uploadData)}`);
}

// Step 3: Create HeyGen video
const videoBody = {
  video_inputs: [{
    character: {
      type: 'avatar',
      avatar_id: $env.HEYGEN_AVATAR_ID,
      avatar_style: 'normal'
    },
    voice: {
      type: 'audio',
      audio_asset_id: assetId
    }
  }],
  dimension: { width: 1280, height: 720 }
};

const videoResp = await fetch('https://api.heygen.com/v2/video/generate', {
  method: 'POST',
  headers: {
    'X-Api-Key': $env.HEYGEN_API_KEY,
    'Content-Type': 'application/json'
  },
  body: JSON.stringify(videoBody)
});

if (!videoResp.ok) {
  throw new Error(`HeyGen create video failed: ${videoResp.status} ${await videoResp.text()}`);
}

const videoData = await videoResp.json();
const videoId = videoData.data?.video_id;
if (!videoId) {
  throw new Error(`HeyGen create video returned no video_id: ${JSON.stringify(videoData)}`);
}

return [{
  json: {
    job_id: jobId,
    video_id: videoId,
    channel_id: channelId,
    user_id: userId
  }
}];

// Poll HeyGen video status (max 20 retries, 30s interval)
const videoId = $input.item.json.video_id;
const jobId = $input.item.json.job_id;
const channelId = $input.item.json.channel_id;
const userId = $input.item.json.user_id;
const apiKey = $env.HEYGEN_API_KEY;

const maxRetries = 20;
const intervalMs = 30000;
let videoUrl = null;
let status = 'processing';

for (let i = 0; i < maxRetries; i++) {
  await new Promise(resolve => setTimeout(resolve, intervalMs));

  const resp = await fetch(`https://api.heygen.com/v1/video_status.get?video_id=${videoId}`, {
    headers: { 'X-Api-Key': apiKey }
  });

  if (!resp.ok) {
    status = 'error';
    break;
  }

  const data = await resp.json();
  status = data.data?.status || 'processing';

  if (status === 'completed') {
    videoUrl = data.data?.video_url;
    break;
  } else if (status === 'failed') {
    break;
  }
  // else continue polling
}

return [{
  json: {
    job_id: jobId,
    video_id: videoId,
    video_url: videoUrl,
    status: status,
    channel_id: channelId,
    user_id: userId,
    completed: status === 'completed'
  }
}];
